#include <bits/stdc++.h>
using namespace std;

string solve(vector<string> &arr, int n){
    // Create a default dictionary to store the count of each element
    map<string, int> count;
    int ma = 0;
    for(int i = 0; i < n; i++){
        count[arr[i]] += 1;
        ma = max(ma, count[arr[i]]);
    }

    int sec_max = 0;
    string ans = "-1";

    // Iterate over the dictionary and find the element which occurs
    // the second most number of times.
    for (pair<string,int> i : count){

        if (i.second > sec_max and i.second < ma){
            sec_max = i.second;
            ans = i.first;
        }
    }
    return ans;
}

int main() {
    int t;
    cin >> t;
    while(t--) {
        int n;
        cin >> n;
        vector<string> arr(n);
        for(int i = 0; i < n; i++) {
            cin >> arr[i];
        }
        cout << solve(arr, n) << endl;
    }
    return 0;
}
